// newInstallCommand creates the "ddx install <name>" command.
func (f *CommandFactory) newInstallCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "install <name>",
		Short: "Install a package or resource",
		Long: `Install a package or resource from the DDx registry into the
current project under .ddx/plugins/<name>/.

Examples:
  ddx install helix                        # Install HELIX workflow
  ddx install helix --force                # Reinstall even if already up to date
  ddx install persona/strict-code-reviewer # Install a single persona`,
		Args: cobra.ExactArgs(1),
		RunE: f.runInstall,
	}
	cmd.Flags().BoolP("force", "f", false, "Reinstall even if already at the latest version")
	cmd.Flags().String("local", "", "Install from a local directory instead of the registry")
	return cmd
}

func (f *CommandFactory) runInstall(cmd *cobra.Command, args []string) error {
	out := cmd.OutOrStdout()
	force, _ := cmd.Flags().GetBool("force")
	name := args[0]

	// Ensure install operations resolve relative paths against the project
	// root (WorkingDir), not the caller's cwd. This prevents creating stale
	// .ddx/ workspaces in subdirectories.
	if f.WorkingDir != "" {
		origDir, _ := os.Getwd()
		if origDir != f.WorkingDir {
			if err := os.Chdir(f.WorkingDir); err == nil {
				defer func() { _ = os.Chdir(origDir) }()
			}
		}
	}

	// Handle --local: install from a local directory instead of registry.
	if localPath, _ := cmd.Flags().GetString("local"); localPath != "" {
		return f.installLocal(name, localPath, force, out)
	}

	if registry.IsResourcePath(name) {
		// Individual resource install (e.g. "persona/strict-code-reviewer")
		fmt.Fprintf(out, "Installing resource %s...\n", name)
		entry, err := registry.InstallResource(name)
		if err != nil {
			return fmt.Errorf("install resource: %w", err)
		}

		state, err := registry.LoadState()
		if err != nil {
			return fmt.Errorf("loading state: %w", err)
		}
		state.AddOrUpdate(entry)
		if err := registry.SaveState(state); err != nil {
			return fmt.Errorf("saving state: %w", err)
		}

		fmt.Fprintf(out, "Installed %s\n", name)
		return nil
	}

	// Package install (e.g. "helix")
	reg := registry.BuiltinRegistry()
	pkg, err := reg.Find(name)
	if err != nil {
		return err
	}

	// Fetch actual latest version from GitHub (overrides hardcoded registry version).
	if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
		pkg.Version = strings.TrimPrefix(release.TagName, "v")
	}

	// Check if already installed at the latest version.
	state, err := registry.LoadState()
	if err == nil {
		for _, e := range state.Installed {
			if e.Name == name {
				if e.Version == pkg.Version {
					if !force {
						fmt.Fprintf(out, "%s %s is already up to date\n", e.Name, e.Version)
						return nil
					}
					fmt.Fprintf(out, "Reinstalling %s %s...\n", e.Name, e.Version)
				} else {
					fmt.Fprintf(out, "Updating %s from %s to %s...\n", e.Name, e.Version, pkg.Version)
				}
			}
		}
	}

	// Capture old file list before installing so we can remove stale files.
	var oldFiles []string
	if state != nil {
		if old := state.FindInstalled(name); old != nil {
			oldFiles = append([]string{}, old.Files...)
		}
	}

	fmt.Fprintf(out, "Installing %s %s from %s...\n", pkg.Name, pkg.Version, pkg.Source)

	entry, err := registry.InstallPackage(pkg, f.WorkingDir)
	if err != nil {
		return fmt.Errorf("install package: %w", err)
	}

	removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
	if removed > 0 {
		fmt.Fprintf(out, "Removed %d stale file(s)\n", removed)
	}

	state, stateErr := registry.LoadState()
	if stateErr != nil {
		return fmt.Errorf("loading state: %w", stateErr)
	}
	state.AddOrUpdate(entry)
	if err := registry.SaveState(state); err != nil {
		return fmt.Errorf("saving state: %w", err)
	}

	fmt.Fprintf(out, "Installed %s %s (%d file(s))\n", pkg.Name, pkg.Version, len(entry.Files))

	// Auto-commit skill symlinks and other trackable changes.
	commitPluginChanges(name, pkg.Version)

	return nil
}

func removeStaleFilesFromInstall(oldFiles []string, newFiles []string) int {
	if len(oldFiles) == 0 {
		return 0
	}

	newSet := make(map[string]bool, len(newFiles))
	for _, f := range newFiles {
		newSet[f] = true
	}

	removed := 0
	for _, f := range oldFiles {
		if newSet[f] {
			continue
		}
		expanded := registry.ExpandHome(f)
		if err := os.RemoveAll(expanded); err == nil {
			removed++
		}
	}
	return removed
}

// commitPluginChanges stages and commits plugin-related changes in the working tree.
// Non-fatal: if git operations fail (not a repo, nothing to commit), it's silently skipped.
func commitPluginChanges(name, version string) {
	// Stage the project-local plugin tree and the skill copies.
	paths := []string{
		filepath.Join(".ddx", "plugins", name) + string(filepath.Separator),
		".agents/skills/",
		".claude/skills/",
	}
	ctx := context.Background()
	for _, p := range paths {
		if _, err := os.Stat(p); err == nil {
			gitAdd := internalgit.Command(ctx, "", "add", p)
			_ = gitAdd.Run()
		}
	}

	// Check if there's anything to commit.
	status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
	if status.Run() == nil {
		return // nothing staged
	}

	msg := fmt.Sprintf("chore: install %s %s", name, version)
	gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
	_ = gitCommit.Run()
}

func prepareSymlinkTarget(target string, force bool) error {
	if info, err := os.Lstat(target); err == nil {
		if info.Mode()&os.ModeSymlink != 0 || force {
			if err := os.RemoveAll(target); err != nil {
				return fmt.Errorf("removing existing %s: %w", target, err)
			}
			return nil
		}
		return fmt.Errorf("%s already exists (use --force to replace)", target)
	} else if !os.IsNotExist(err) {
		return fmt.Errorf("checking existing %s: %w", target, err)
	}
	return nil
}

// installLocal installs a plugin from a local directory into the project
// under .ddx/plugins/<name>/. The plugin tree is copied — never symlinked
// out to a developer checkout. Skills are routed through skills.Install
// (real-file copies into .agents/skills/ + .claude/skills/).

// Package federation defines the hub-side federation registry: state types,
// persistence, and reconciliation helpers. No HTTP layer here — that lands in
// later beads. The on-disk format carries a schema_version field for forward
// compatibility (see ADR-007 and FEAT-026).
package federation

import (
	"fmt"
	"time"
)

// CurrentSchemaVersion is the schema_version this build writes. Reading code
// must accept older versions and migrate; writing code always emits this.
const CurrentSchemaVersion = "1"

// SpokeStatus is the lifecycle/health status of a registered spoke.
//
// The states are:
//   - StatusRegistered: spoke has registered but no heartbeat has been observed yet.
//   - StatusActive:     last heartbeat is recent (the live/healthy state).
//   - StatusStale:      no heartbeat for ≥ 2 minutes.
//   - StatusOffline:    fan-out to the spoke failed (connection refused, unreachable).
//   - StatusDegraded:   version handshake accepted with minor/schema drift.
//
// The bead-level enum collapses ADR-007's split between compat_status and
// liveness into a single field for v1 persistence; richer surface fields can
// be added in later schema versions without breaking older readers.
type SpokeStatus string

const (
	StatusRegistered SpokeStatus = "registered"
	StatusActive     SpokeStatus = "active"
	StatusStale      SpokeStatus = "stale"
	StatusOffline    SpokeStatus = "offline"
	StatusDegraded   SpokeStatus = "degraded"
)

// Valid reports whether s is one of the known status values.
func (s SpokeStatus) Valid() bool {
	switch s {
	case StatusRegistered, StatusActive, StatusStale, StatusOffline, StatusDegraded:
		return true
	}
	return false
}

// SpokeRecord is one entry in the federation registry.
type SpokeRecord struct {
	NodeID        string      `json:"node_id"`
	Name          string      `json:"name"`
	URL           string      `json:"url"`
	DDxVersion    string      `json:"ddx_version,omitempty"`
	SchemaVersion string      `json:"schema_version,omitempty"`
	Capabilities  []string    `json:"capabilities,omitempty"`
	RegisteredAt  time.Time   `json:"registered_at"`
	LastHeartbeat time.Time   `json:"last_heartbeat"`
	Status        SpokeStatus `json:"status"`
}

// FederationRegistry is the persisted hub state.
type FederationRegistry struct {
	SchemaVersion string        `json:"schema_version"`
	Spokes        []SpokeRecord `json:"spokes"`
}

// NewRegistry returns an empty registry stamped with the current schema version.
func NewRegistry() *FederationRegistry {
	return &FederationRegistry{
		SchemaVersion: CurrentSchemaVersion,
		Spokes:        []SpokeRecord{},
	}
}

// FindSpoke returns the record for nodeID, or nil if absent.
func (r *FederationRegistry) FindSpoke(nodeID string) *SpokeRecord {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			return &r.Spokes[i]
		}
	}
	return nil
}

// UpsertSpoke inserts or replaces a spoke by NodeID. NodeID must be non-empty.
func (r *FederationRegistry) UpsertSpoke(rec SpokeRecord) error {
	if rec.NodeID == "" {
		return fmt.Errorf("federation: spoke node_id is required")
	}
	if rec.Status == "" {
		rec.Status = StatusRegistered
	}
	if !rec.Status.Valid() {
		return fmt.Errorf("federation: invalid spoke status %q", rec.Status)
	}
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == rec.NodeID {
			r.Spokes[i] = rec
			return nil
		}
	}
	r.Spokes = append(r.Spokes, rec)
	return nil
}

// RemoveSpoke removes a spoke by NodeID; reports whether it was present.
func (r *FederationRegistry) RemoveSpoke(nodeID string) bool {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			r.Spokes = append(r.Spokes[:i], r.Spokes[i+1:]...)
			return true
		}
	}
	return false
}

// SetStatus updates the status of a spoke and returns true on success. Refuses
// unknown status values so callers cannot silently corrupt persisted state.
func (r *FederationRegistry) SetStatus(nodeID string, status SpokeStatus) error {
	if !status.Valid() {
		return fmt.Errorf("federation: invalid status %q", status)
	}
	rec := r.FindSpoke(nodeID)
	if rec == nil {
		return fmt.Errorf("federation: spoke %q not found", nodeID)
	}
	rec.Status = status
	return nil
}

// ReconcileLiveness derives status purely from elapsed time since the last
// heartbeat for spokes whose status is currently in {registered, active,
// stale}. Statuses set externally (offline from fan-out failure, degraded from
// version handshake) are left alone — those are not time-driven.
//
//   - now - last_heartbeat <  staleAfter            → active
//   - now - last_heartbeat >= staleAfter            → stale
//
// A zero LastHeartbeat keeps a freshly-registered spoke in StatusRegistered
// until the first heartbeat is observed.
func (r *FederationRegistry) ReconcileLiveness(now time.Time, staleAfter time.Duration) {
	for i := range r.Spokes {
		s := &r.Spokes[i]
		switch s.Status {
		case StatusOffline, StatusDegraded:
			continue
		}
		if s.LastHeartbeat.IsZero() {
			s.Status = StatusRegistered
			continue
		}
		if now.Sub(s.LastHeartbeat) >= staleAfter {
			s.Status = StatusStale
		} else {
			s.Status = StatusActive
		}
	}
}

package registry

import (
	"fmt"
	"io/fs"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/skills"
)

// AuditInstalledEntry checks one installed package entry for plugin issues.
func AuditInstalledEntry(entry InstalledEntry, fallback *Package) []ValidationIssue {
	var issues []ValidationIssue
	root := installedRootPath(entry)
	if root == "" {
		issues = append(issues, ValidationIssue{Message: fmt.Sprintf("installed entry %q has no recorded plugin root", entry.Name)})
		return issues
	}

	issues = append(issues, auditRecordedFiles(entry)...)

	manifest, manifestMissing, manifestIssues := loadPackageDefinitionForAudit(root, fallback)
	issues = append(issues, manifestIssues...)

	if manifestMissing {
		issues = append(issues, ValidationIssue{
			Path:    filepath.Join(root, "package.yaml"),
			Message: "missing package.yaml",
		})
	}

	if manifest == nil {
		manifest = &Package{}
	}

	issues = append(issues, ValidatePackageStructure(root, manifest)...)
	return issues
}

// ValidatePackageStructure checks the skill, symlink, and executable layout
// for a package root before install or after install-state recovery.
func ValidatePackageStructure(root string, pkg *Package) []ValidationIssue {
	if pkg == nil {
		return []ValidationIssue{{Path: filepath.Join(root, "package.yaml"), Message: "missing package definition"}}
	}
	return auditPluginRoot(root, pkg)
}

func loadPackageDefinitionForAudit(root string, fallback *Package) (*Package, bool, []ValidationIssue) {
	manifest, manifestMissing, issues, err := LoadPackageManifestWithFallback(root, fallback)
	if err == nil || os.IsNotExist(err) {
		// Report validation issues even when package is valid, so audit shows schema problems.
		return manifest, manifestMissing, issues
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so structural audits can proceed.
	if manifest != nil {
		return manifest, false, issues
	}

	if len(issues) == 0 {
		issues = append(issues, ValidationIssue{Path: filepath.Join(root, "package.yaml"), Message: err.Error()})
	}
	return manifest, false, issues
}

func auditPluginRoot(root string, pkg *Package) []ValidationIssue {
	var issues []ValidationIssue

	if pkg.APIVersion != "" && pkg.APIVersion != SupportedPackageAPIVersion {
		issues = append(issues, ValidationIssue{
			Path:    filepath.Join(root, "package.yaml"),
			Message: fmt.Sprintf("unsupported `api_version` %q (supported: %s)", pkg.APIVersion, SupportedPackageAPIVersion),
		})
	}

	ignoredBrokenSymlinkPaths := collectIgnoredBrokenSymlinkPaths(root, pkg)
	for _, symlinkIssue := range auditBrokenSymlinks(root, ignoredBrokenSymlinkPaths) {
		issues = append(issues, symlinkIssue)
	}

	for _, skillRoot := range collectSkillRoots(root, pkg) {
		issues = append(issues, auditSkillRoot(root, skillRoot)...)
	}

	for _, rel := range pkg.Install.Executable {
		issues = append(issues, auditExecutable(root, rel)...)
	}

	return issues
}

func auditRecordedFiles(entry InstalledEntry) []ValidationIssue {
	var issues []ValidationIssue
	seen := map[string]bool{}
	recordedPaths := append([]string(nil), entry.Files...)
	if root := installedRootPath(entry); root != "" {
		recordedPaths = append(recordedPaths, root)
	}
	for _, recorded := range recordedPaths {
		path := ExpandHome(recorded)
		if path == "" || seen[path] {
			continue
		}
		seen[path] = true
		info, err := os.Lstat(path)
		if err != nil {
			if os.IsNotExist(err) {
				// Pre-migration entries whose paths begin with ~ are outside the
				// project root; treat missing paths as no-op (no issue raised).
				if strings.HasPrefix(recorded, "~") {
					continue
				}
				issues = append(issues, ValidationIssue{Path: path, Message: "missing recorded file or symlink"})
				continue
			}
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			continue
		}
		if info.Mode()&os.ModeSymlink == 0 {
			continue
		}

		target, err := os.Readlink(path)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
			continue
		}
		if !filepath.IsAbs(target) {
			target = filepath.Join(filepath.Dir(path), target)
		}
		if _, err := os.Stat(target); err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
		}
	}
	return issues
}

func auditBrokenSymlinks(root string, ignored map[string]bool) []ValidationIssue {
	var issues []ValidationIssue
	walkRoot := root
	if resolved, err := filepath.EvalSymlinks(root); err == nil && resolved != "" {
		walkRoot = resolved
	}

	_ = filepath.WalkDir(walkRoot, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			return nil
		}
		if path == walkRoot {
			return nil
		}

		info, err := os.Lstat(path)
		if err != nil {
			if os.IsNotExist(err) {
				issues = append(issues, ValidationIssue{Path: path, Message: "missing installed file"})
				return nil
			}
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			return nil
		}
		if info.Mode()&os.ModeSymlink == 0 {
			return nil
		}
		if ignored != nil && ignored[path] {
			return nil
		}

		target, err := os.Readlink(path)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
			return nil
		}
		if !filepath.IsAbs(target) {
			target = filepath.Join(filepath.Dir(path), target)
		}
		if _, err := os.Stat(target); err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
		}
		return nil
	})

	return issues
}

func collectSkillRoots(root string, pkg *Package) []string {
	seen := map[string]bool{}
	var roots []string

	add := func(candidate string) {
		if strings.TrimSpace(candidate) == "" {
			return
		}
		abs := candidate
		if resolved, err := filepath.EvalSymlinks(candidate); err == nil && resolved != "" {
			abs = resolved
		} else if resolved, err := filepath.Abs(candidate); err == nil && resolved != "" {
			abs = resolved
		}
		if seen[abs] {
			return
		}
		if _, err := os.Stat(candidate); err != nil {
			return
		}
		seen[abs] = true
		roots = append(roots, candidate)
	}

	for _, mapping := range pkg.Install.Skills {
		sourceRoot := filepath.Join(root, filepath.FromSlash(mapping.Source))
		add(sourceRoot)

		cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
		switch cleanSource {
		case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
			add(filepath.Join(root, "skills"))
		}
	}

	return roots
}

func collectIgnoredBrokenSymlinkPaths(root string, pkg *Package) map[string]bool {
	ignored := make(map[string]bool)
	for _, mapping := range pkg.Install.Skills {
		cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
		switch cleanSource {
		case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
			skillRoot := filepath.Join(root, cleanSource)
			entries, err := os.ReadDir(skillRoot)
			if err != nil {
				continue
			}
			for _, entry := range entries {
				ignored[filepath.Join(skillRoot, entry.Name())] = true
			}
		}
	}
	return ignored
}

func auditSkillRoot(packageRoot, root string) []ValidationIssue {
	var issues []ValidationIssue

	info, err := os.Stat(root)
	if err != nil {
		issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
		return issues
	}
	if !info.IsDir() {
		issues = append(issues, ValidationIssue{Path: root, Message: "expected a skill directory"})
		return issues
	}

