type federationHeartbeatRequest struct {
	NodeID string `json:"node_id"`
}

func (s *Server) handleFederationHeartbeat(w http.ResponseWriter, r *http.Request) {
	var req federationHeartbeatRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid json: " + err.Error()})
		return
	}
	req.NodeID = strings.TrimSpace(req.NodeID)
	if req.NodeID == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "node_id required"})
		return
	}

	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()

	rec := s.hub.registry.FindSpoke(req.NodeID)
	if rec == nil {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "spoke not registered"})
		return
	}
	now := s.hub.now().UTC()
	rec.LastHeartbeat = now
	// Heartbeat clears registered-on-first-seen and offline; preserves
	// degraded (set by the version handshake at registration time).
	if rec.Status == federation.StatusRegistered || rec.Status == federation.StatusOffline || rec.Status == federation.StatusStale {
		rec.Status = federation.StatusActive
	}
	s.persistFederationLocked()

	writeJSON(w, http.StatusOK, map[string]any{
		"node_id":        rec.NodeID,
		"status":         rec.Status,
		"last_heartbeat": rec.LastHeartbeat,
	})
}

func (s *Server) handleFederationListSpokes(w http.ResponseWriter, _ *http.Request) {
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	out := make([]federation.SpokeRecord, 0, len(s.hub.registry.Spokes))
	out = append(out, s.hub.registry.Spokes...)
	writeJSON(w, http.StatusOK, map[string]any{
		"schema_version": s.hub.registry.SchemaVersion,
		"spokes":         out,
	})
}

func (s *Server) handleFederationDeregister(w http.ResponseWriter, r *http.Request) {
	id := strings.TrimSpace(r.PathValue("id"))
	if id == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id required"})
		return
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	if !s.hub.registry.RemoveSpoke(id) {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "spoke not found"})
		return
	}
	s.persistFederationLocked()
	writeJSON(w, http.StatusOK, map[string]string{"node_id": id, "status": "deregistered"})
}

// persistFederationLocked saves the registry to disk if a state path is set.
// Caller must hold s.hub.mu.
func (s *Server) persistFederationLocked() {
	if s.hub.statePath == "" {
		return
	}
	if err := federation.SaveStateTo(s.hub.statePath, s.hub.registry); err != nil {
		s.hub.warnLog("federation: persist state: %v", err)
	}
}

# go-production-reachability

A REACH-PROTO conforming pre-merge check that fails when a diff introduces
new Go functions or methods that are **not reachable** from any production
entry point.

This check is **opt-in**: `ddx init` does not install it (a Go-specific
opinion would leak through to non-Go projects). Operators copy
`check.yaml` into their project's `.ddx/checks/` directory and customize
the entry-root packages.

## What it catches

`git checkout` a feature branch where someone added `func ProcessOrder()`
in `internal/orders/orders.go`, but forgot to wire it into any handler,
command, or main package. `go build` succeeds. Tests of the new function
pass. The function is dead in production. This check stops that merge.

## How it works

Given the protocol-injected env vars `DIFF_BASE`, `DIFF_HEAD`,
`PROJECT_ROOT`, `EVIDENCE_DIR`, the check:

1. Parses `git diff --name-only --diff-filter=AM DIFF_BASE..DIFF_HEAD -- '*.go'`
   (excluding `_test.go`).
2. For each changed file, parses the `DIFF_BASE` AST and the `HEAD` AST
   and computes the set of newly-added top-level `FuncDecl`s by qualified
   name (plain functions, value-receiver methods `T.M`, pointer-receiver
   methods `(*T).M`).
3. Runs `golang.org/x/tools/cmd/deadcode -json` from the configured
   module directory over the configured packages. Test files are excluded
   from the dead-set so a unit-test-only call does **not** satisfy the
   check.
4. For each new symbol whose declaration line matches a dead-function
   entry → emit a `kind=unreachable` violation.
5. Looks for `// wiring:pending <bead-id>` on the symbol's doc comment.
   If present, validates the bead exists in `.ddx/beads.jsonl` and is
   `open` / `in_progress` / `ready`. Invalid annotations are themselves
   violations (`kind=invalid_annotation`).
6. Writes `${EVIDENCE_DIR}/${CHECK_NAME}.json` with the protocol schema:

   ```json
   {
     "status": "pass" | "block" | "error",
     "message": "...",
     "violations": [{"file":"...","line":0,"symbol":"...","kind":"...","detail":"..."}]
   }
   ```

## Installing

```bash
mkdir -p .ddx/checks
cp library/checks/go-production-reachability/check.yaml \
   .ddx/checks/production-reachability.yaml
$EDITOR .ddx/checks/production-reachability.yaml   # set --module-dir / --packages
```

Verify with:

```bash
ddx ac run <bead-id>
```

## Flags

| flag           | default                 | meaning                                              |
| -------------- | ----------------------- | ---------------------------------------------------- |
| `--module-dir` | `.`                     | directory containing `go.mod` (relative to `PROJECT_ROOT`) |
| `--packages`   | `./...`                 | comma-separated package patterns passed to deadcode  |
| `--deadcode`   | (auto)                  | path to deadcode binary; auto-detects PATH or `go run` |
| `--beads-file` | `.ddx/beads.jsonl`      | beads ledger used to validate `wiring:pending`       |
| `--name`       | `$CHECK_NAME`           | basename for the result file                         |

## Escape hatch

```go
// wiring:pending ddx-1234abcd
//
// Will be called from cmd/migrate.go once the migration plan lands.
func MigrateOrders(ctx context.Context) error { /* ... */ }
```

The annotation is rejected (and itself becomes a violation) when:

- the named bead does not exist in `.ddx/beads.jsonl`, or
- the bead's status is closed (only `open`, `in_progress`, `ready` accepted).

## Limitations

- Only `FuncDecl`s are evaluated (functions and methods). New types and
  exported variables are not checked because RTA reachability is defined
  over functions; type-only changes are caught by the Go compiler when
  unused.
- The configured entry packages must contain at least one `main` package
  for deadcode to start its RTA traversal.
- Generated files are deferred to deadcode's own `Generated` flag.

---
# go-production-reachability — TEMPLATE
#
# Copy this file to .ddx/checks/production-reachability.yaml in your project
# and customize the `--module-dir` and `--packages` flags below to point at
# your Go module and entry-root packages.
#
# This check fails (status=block) when the diff introduces a Go function or
# method that is not reachable from any main entry point under the configured
# package roots, ensuring new code is wired into the production call graph
# before it can be merged.
#
# REQUIREMENTS
#   - golang.org/x/tools/cmd/deadcode on PATH, or `go` available so the
#     check can `go run golang.org/x/tools/cmd/deadcode@v0.42.0` on demand.
#   - PROJECT_ROOT is a git working tree.
#
# ESCAPE HATCH
#   Annotate a deliberately-unwired declaration with
#       // wiring:pending <bead-id>
#   on the doc-comment line preceding the func. The check looks up the bead
#   in .ddx/beads.jsonl and accepts the annotation only if the bead exists
#   and is open / in_progress / ready. Closed or missing beads → violation.

name: production-reachability
when: pre_merge
applies_to:
  paths:
    - "*.go"
command: |
  cd library/checks/go-production-reachability && \
    go run . \
      --module-dir=cli \
      --packages=./...

---
// Package main implements the Go-specific production-reachability check
// conforming to the REACH-PROTO check protocol (see cli/internal/checks/protocol.go).
//
// It reports newly-added Go functions/methods that are not reachable from the
// project's configured entry roots, using golang.org/x/tools/cmd/deadcode
// (Rapid Type Analysis) as the underlying reachability engine.
package main

import (
	"bufio"
	"encoding/json"
	"flag"
	"fmt"
	"go/ast"
	"go/parser"
	"go/token"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

type violation struct {
	File   string `json:"file,omitempty"`
	Line   int    `json:"line,omitempty"`
	Symbol string `json:"symbol,omitempty"`
	Kind   string `json:"kind,omitempty"`
	Detail string `json:"detail,omitempty"`
}

type result struct {
	Status     string      `json:"status"`
	Message    string      `json:"message,omitempty"`
	Violations []violation `json:"violations,omitempty"`
}

func main() {
	var (
		moduleDir     string
		packagesArg   string
		deadcodeBin   string
		beadsFile     string
		checkName     string
	)
	flag.StringVar(&moduleDir, "module-dir", ".", "Directory holding the go.mod from which deadcode is run (relative to PROJECT_ROOT)")
	flag.StringVar(&packagesArg, "packages", "./...", "Comma-separated package patterns passed to deadcode")
	flag.StringVar(&deadcodeBin, "deadcode", "", "Path to deadcode binary; default uses 'go run golang.org/x/tools/cmd/deadcode@v0.42.0'")
	flag.StringVar(&beadsFile, "beads-file", ".ddx/beads.jsonl", "Path to beads.jsonl (relative to PROJECT_ROOT)")
	flag.StringVar(&checkName, "name", "", "Override check name (default from CHECK_NAME env)")
	flag.Parse()

	projectRoot := envOr("PROJECT_ROOT", "")
	evidenceDir := envOr("EVIDENCE_DIR", "")
	diffBase := envOr("DIFF_BASE", "")
	diffHead := envOr("DIFF_HEAD", "HEAD")
	if checkName == "" {
		checkName = envOr("CHECK_NAME", "production-reachability")
	}
	if projectRoot == "" || evidenceDir == "" {
		emitFatal(evidenceDir, checkName, "missing required env: PROJECT_ROOT and EVIDENCE_DIR must be set")
		return
	}
	if err := os.MkdirAll(evidenceDir, 0o755); err != nil {
		emitFatal(evidenceDir, checkName, "create evidence dir: "+err.Error())
		return
	}

	res := run(runArgs{
		ProjectRoot: projectRoot,
		ModuleDir:   moduleDir,
		Packages:    splitCSV(packagesArg),
		DeadcodeBin: deadcodeBin,
		BeadsFile:   filepath.Join(projectRoot, beadsFile),
		DiffBase:    diffBase,
		DiffHead:    diffHead,
		EntryRoots:  splitCSV(packagesArg),
	})

	writeResult(filepath.Join(evidenceDir, checkName+".json"), res)
}

type runArgs struct {
	ProjectRoot string
	ModuleDir   string
	Packages    []string
	EntryRoots  []string
	DeadcodeBin string
	BeadsFile   string
	DiffBase    string
	DiffHead    string
}

func run(a runArgs) result {
	if a.DiffBase == "" || a.DiffBase == a.DiffHead {
		return result{Status: "pass", Message: "no diff range; nothing to evaluate"}
	}

	changedGoFiles, err := gitChangedGoFiles(a.ProjectRoot, a.DiffBase, a.DiffHead)
	if err != nil {
		return result{Status: "error", Message: "git diff: " + err.Error()}
	}
	if len(changedGoFiles) == 0 {
		return result{Status: "pass", Message: "no non-test Go files changed"}
	}

	newSyms, err := newSymbols(a.ProjectRoot, a.DiffBase, changedGoFiles)
	if err != nil {
		return result{Status: "error", Message: "scan new symbols: " + err.Error()}
	}
	if len(newSyms) == 0 {
		return result{Status: "pass", Message: "no new top-level functions or methods added"}
	}

	deadSet, err := runDeadcode(a)
	if err != nil {
		return result{Status: "error", Message: "deadcode: " + err.Error()}
	}

	var violations []violation
	for _, s := range newSyms {
		if !isDead(s, deadSet) {
			continue
		}
		ann := s.Annotation
		if ann != "" {
			ok, why := validatePending(a.BeadsFile, ann)
			if ok {
				continue
			}
			violations = append(violations, violation{
				File:   relPath(a.ProjectRoot, s.AbsFile),
				Line:   s.Line,
				Symbol: s.Symbol,
				Kind:   "invalid_annotation",
				Detail: fmt.Sprintf("// wiring:pending %s rejected: %s", ann, why),
			})
			continue
		}
		violations = append(violations, violation{
			File:   relPath(a.ProjectRoot, s.AbsFile),
			Line:   s.Line,
			Symbol: s.Symbol,
			Kind:   "unreachable",
			Detail: fmt.Sprintf("no path from entry roots: %s", strings.Join(a.EntryRoots, ",")),
		})
	}

	if len(violations) == 0 {
		return result{Status: "pass", Message: fmt.Sprintf("%d new symbol(s) all reachable from entry roots", len(newSyms))}
	}
	return result{
		Status:     "block",
		Message:    fmt.Sprintf("%d new symbol(s) unreachable from entry roots", len(violations)),
		Violations: violations,
	}
}

// symbol describes one newly-added top-level function or method declaration
// from the worktree side of the diff.
type symbol struct {
	AbsFile    string // absolute path
	Line       int    // declaration line in HEAD
	Symbol     string // "Func" or "(*T).Method" or "T.Method"
	Annotation string // bead-id named in `// wiring:pending <bead-id>`, else ""
}

// newSymbols returns top-level FuncDecls present in the worktree (HEAD)
// version of each changed file but absent from the DIFF_BASE version,
// keyed by (file, qualified symbol name). Test files are skipped.
func newSymbols(projectRoot, diffBase string, files []string) ([]symbol, error) {
	var out []symbol
	for _, rel := range files {
		abs := filepath.Join(projectRoot, rel)
		newSrc, err := os.ReadFile(abs)
		if err != nil {
			// File deleted in HEAD — nothing to add.
			continue
		}
		oldSrc, _ := gitShow(projectRoot, diffBase, rel) // empty on add
		oldDecls := declSet(oldSrc, rel)
		fset := token.NewFileSet()
		f, err := parser.ParseFile(fset, abs, newSrc, parser.ParseComments)
		if err != nil {
			return nil, fmt.Errorf("parse %s: %w", rel, err)
		}
		for _, decl := range f.Decls {
			fd, ok := decl.(*ast.FuncDecl)
			if !ok {
				continue
			}
			qn := qualName(fd)
			if _, existed := oldDecls[qn]; existed {
				continue
			}
			pos := fset.Position(fd.Pos())
			out = append(out, symbol{
				AbsFile:    abs,
				Line:       pos.Line,
				Symbol:     qn,
				Annotation: extractPendingBead(fd),
			})
		}
	}
	return out, nil
}

func declSet(src []byte, displayName string) map[string]struct{} {
	out := map[string]struct{}{}
	if len(src) == 0 {
		return out
	}
	fset := token.NewFileSet()
	f, err := parser.ParseFile(fset, displayName, src, 0)
	if err != nil {
		return out
	}
	for _, decl := range f.Decls {
		if fd, ok := decl.(*ast.FuncDecl); ok {
			out[qualName(fd)] = struct{}{}
		}

